async_await_13.complete:
interface Meteo {
    temperature: number;
    ville: string;
}
async function obtenirMeteo(ville: string): Promise<Meteo> {
    const reponse = await fetch(`https://api.meteo.test/${ville}`);
    const donnees: Meteo = await reponse.json();
    return donnees;
}
obtenirMeteo("Paris").then(res => console.log(res.temperature));

file_io_14.complete:
import { writeFile, readFile } from 'fs/promises';
async function stockerConfiguration(config: Record<string, any>): Promise<void> {
    const fichier = './config.json';
    const chaineJson = JSON.stringify(config, null, 2);
    await writeFile(fichier, chaineJson, 'utf-8');
}
async function lireConfiguration(): Promise<Record<string, any>> {
    const brut = await readFile('./config.json', 'utf-8');
    return JSON.parse(brut);
}
